type Tone = "slate" | "pink" | "green" | "amber" | "red" | "violet" | "blue" | "dark"
function Badge({ children, tone = "slate" }: { children: React.ReactNode; tone?: Tone }) {
  const m: Record<Tone, string> = { slate: "bg-slate-100 text-slate-700 border-slate-200", pink: "bg-pink-50 text-pink-700 border-pink-200", green: "bg-emerald-50 text-emerald-700 border-emerald-200", amber: "bg-amber-50 text-amber-700 border-amber-200", red: "bg-red-50 text-red-700 border-red-200", violet: "bg-violet-50 text-violet-700 border-violet-200", blue: "bg-blue-50 text-blue-700 border-blue-200", dark: "bg-white text-slate-950 border-slate-200" }
  return <span className={cn("rounded-full border px-3 py-1 text-[11px] font-black uppercase tracking-wide", m[tone])}>{children}</span>
}
function statusTone(s: SeoStatus): Tone { return s === "published" || s === "approved" ? "green" : s === "rejected" ? "red" : s === "review" ? "violet" : s === "writing" ? "amber" : s === "archived" ? "dark" : s === "brief" ? "blue" : "slate" }
function priorityTone(p: string): Tone { return p === "urgent" ? "red" : p === "high" ? "amber" : p === "normal" ? "blue" : "slate" }
function pct(v: number) { return `${Math.min(100, Math.max(0, Math.round(v || 0)))}%` }
function Panel({ title, subtitle, icon: Icon, children, dark = false, actions }: { title: string; subtitle?: string; icon: any; children: React.ReactNode; dark?: boolean; actions?: React.ReactNode }) {
  return <section className={cn("rounded-[2rem] border p-5 shadow-sm", dark ? "border-slate-200 bg-white text-slate-950" : "border-slate-200 bg-white text-slate-950")}>
    <div className="flex flex-wrap items-start justify-between gap-3"><div><h2 className={cn("flex items-center gap-2 text-lg font-black", dark ? "text-slate-950" : "text-slate-950")}><Icon className={cn("h-5 w-5", dark ? "text-pink-300" : "text-pink-600")} />{title}</h2>{subtitle ? <p className={cn("mt-1 text-sm font-semibold", dark ? "text-slate-950/70" : "text-slate-9500")}>{subtitle}</p> : null}</div>{actions}</div>
    <div className="mt-5">{children}</div>
  </section>
}
function Metric({ label, value, icon: Icon, sub, tone="pink" }: { label: string; value: string | number; icon: any; sub: string; tone?: Tone }) {
  return <div className="rounded-[1.7rem] border border-slate-200 bg-white/10 p-5 shadow-xl backdrop-blur"><Icon className={cn("h-5 w-5", tone === "green" ? "text-emerald-200" : tone === "amber" ? "text-amber-200" : tone === "blue" ? "text-blue-200" : "text-pink-200")} /><p className="mt-4 text-[11px] font-black uppercase tracking-[0.2em]" style={{ color: "rgba(255,255,255,.75)" }}>{label}</p><p className="mt-1 text-3xl font-black" style={{ color: "#fff" }}>{value}</p><p className="mt-1 text-xs font-bold" style={{ color: "rgba(255,255,255,.65)" }}>{sub}</p></div>
}
function Field({ label, children }: { label: string; children: React.ReactNode }) { return <label className="block"><span className="mb-2 block text-xs font-black uppercase tracking-widest text-slate-9500">{label}</span>{children}</label> }
