type Mode = "create" | "editor" | "edit" | "delete" | "calendar" | "review" | "optimizer" | "clusters" | "publishing" | "governance" | "analytics" | "linking"
const MODE_META: Record<Mode, { title: string; subtitle: string; icon: any; cta: string }> = {
  create: { title: "Create SEO / Blog Operation", subtitle: "Brief a new article, landing page, guide, FAQ, service page or communication asset with strict SEO and brand control.", icon: FilePlus2, cta: "Create task" },
  editor: { title: "SEO Article Command Room", subtitle: "Open, view, score, approve, publish, duplicate, edit and control one SEO task.", icon: FileText, cta: "Save task" },
  edit: { title: "Edit SEO / Blog Task", subtitle: "Change the content strategy, metadata, keyword, owner, timeline and publishing readiness.", icon: Pencil, cta: "Save changes" },
  delete: { title: "Delete / Archive Control", subtitle: "Protect the workspace from accidental deletion with clear archive and permanent removal controls.", icon: Trash2, cta: "Archive safely" },
  calendar: { title: "Editorial Calendar Control", subtitle: "Control upcoming publishing, deadlines, blockers and production rhythm.", icon: CalendarDays, cta: "Schedule outputs" },
  review: { title: "Review and Approval Command", subtitle: "Approve, reject, return to writing, or publish SEO content with governance checks.", icon: ClipboardCheck, cta: "Approve reviewed" },
  optimizer: { title: "SEO Optimizer Lab", subtitle: "Improve keyword focus, metadata, internal links, readability and conversion quality.", icon: Wand2, cta: "Optimize selected" },
  clusters: { title: "Topic Cluster Strategy", subtitle: "Build content authority through pillar pages, support articles, service pages and internal linking.", icon: Network, cta: "Build cluster" },
  publishing: { title: "Publishing Desk", subtitle: "Prepare final status, URL, approvals, calendar and post-publication follow-up.", icon: UploadCloud, cta: "Publish ready" },
  governance: { title: "Brand Governance Center", subtitle: "Ensure tone, claims, legal comfort, brand voice, local credibility and communication consistency.", icon: ShieldCheck, cta: "Validate brand" },
  analytics: { title: "SEO Analytics Control", subtitle: "Summarize ranking readiness, production bottlenecks, publishing ratio and content conversion quality.", icon: BarChart3, cta: "Refresh analytics" },
  linking: { title: "Internal Linking Map", subtitle: "Connect articles, service pages, contact pages, partner pages and Academy proof routes.", icon: Link2, cta: "Apply linking" },
}

export function SeoExecutiveSubpage({ mode, taskId }: { mode: Mode; taskId?: string }) {
  const meta = MODE_META[mode]
  const [items, setItems] = useState<SeoItem[]>([])
  const [selectedId, setSelectedId] = useState(taskId || "")
  const [draft, setDraft] = useState<SeoItem>({ ...emptySeoItem, id: `seo-${Date.now()}`, created_at: new Date().toISOString() })
  const [note, setNote] = useState("Workspace ready.")
  const [logs, setLogs] = useState<any[]>([])

  useEffect(() => {
    const loaded = createSeoSeedIfEmpty()
    setItems(loaded)
    const id = taskId || loaded[0]?.id || ""
    setSelectedId(id)
    const found = loaded.find(i => i.id === id)
    if (found) setDraft(found)
    setLogs(loadSeoLogs())
  }, [taskId])

  const selected = useMemo(() => items.find(i => i.id === selectedId) || draft, [items, selectedId, draft])
  const warnings = useMemo(() => seoReadinessWarnings(selected), [selected])
  const statusCounts = useMemo(() => SEO_STATUSES.map(status => ({ status, count: items.filter(i => i.status === status).length })), [items])

  function update(patch: Partial<SeoItem>) { setDraft(prev => scoreItem({ ...prev, ...patch })) }
  function save(action = "save") {
    const clean = scoreItem({ ...draft, id: draft.id || `seo-${Date.now()}`, slug: draft.slug || slugify(draft.title || draft.primary_keyword || "seo-task"), updated_at: new Date().toISOString() })
    const exists = items.some(i => i.id === clean.id)
    const next = exists ? items.map(i => i.id === clean.id ? clean : i) : [clean, ...items]
    persistSeoItems(next); setItems(next); setSelectedId(clean.id); setDraft(clean); setNote(`${action} synced.`); setLogs(addSeoLog({ itemId: clean.id, action, actor: "SEO Executive", note: `${meta.title}: ${clean.title}` }))
  }
  function status(status: SeoStatus) { update({ status, approval_status: status }); setTimeout(() => save(`status:${status}`), 0) }
  function remove(permanent = false) {
    if (!selected?.id) return
    if (permanent) { if (!window.confirm("Permanently delete this SEO task?")) return; const next = deleteSeoItem(selected.id); setItems(next); setDraft(next[0] || { ...emptySeoItem, id: `seo-${Date.now()}` }); setSelectedId(next[0]?.id || ""); setNote("Task permanently deleted.") }
    else { update({ status: "archived", approval_status: "archived" }); setTimeout(() => save("archive"), 0) }
  }
  function autoFill(kind: string) {
    if (kind === "meta") update({ meta_title: draft.meta_title || `${draft.title || "AngelCare guide"} | AngelCare`, meta_description: draft.meta_description || "Découvrez une solution AngelCare fiable, humaine et organisée. Contactez-nous pour une orientation rapide." })
    if (kind === "outline") update({ outline: `${draft.outline}\nH1 ${draft.title || "AngelCare guide"}\nH2 Search intent\nH2 AngelCare solution\nH2 Trust proof\nH2 FAQ\nH2 Contact CTA`.trim() })
    if (kind === "links") update({ internal_links: `${draft.internal_links}\n/services\n/contact\n/academy\n/partners\n/blog`.trim() })
    if (kind === "intent") update({ search_intent: draft.search_intent || "The user needs trustworthy practical guidance, local credibility and a clear next step to contact AngelCare." })
    setNote(`${kind} generated.`)
  }

  return <main data-market-os-root className="min-h-screen bg-[radial-gradient(circle_at_top_left,#ffe4f0,transparent_28%),linear-gradient(180deg,#f8fafc,#eef2f7)] p-5 text-slate-950 md:p-8">
    <section className="mx-auto max-w-[1800px] space-y-6">
      <header className="overflow-hidden rounded-[2.8rem] bg-white text-slate-950 shadow-2xl"><div className="relative grid gap-6 p-7 xl:grid-cols-[1.3fr_.9fr]"><div className="absolute right-0 top-0 h-80 w-80 rounded-full bg-pink-500/20 blur-3xl" /><div className="relative z-10"><div className="flex flex-wrap gap-2"><Badge tone="pink">SEO / Blog</Badge><Badge tone="violet">{mode}</Badge><Badge tone="green">Executive control</Badge></div><h1 className="mt-5 text-4xl font-black tracking-tight md:text-6xl" style={{ color: "#fff" }}>{meta.title}</h1><p className="mt-4 max-w-4xl text-sm font-semibold leading-7" style={{ color: "rgba(255,255,255,.82)" }}>{meta.subtitle}</p><div className="mt-6 flex flex-wrap gap-3"><Link href="/market-os/seo-blog-workspace" className={cn(button,"border border-slate-200 bg-white/10 text-slate-950")}><ArrowRight className="mr-2 h-4 w-4 rotate-180" />Back to SEO command</Link><button onClick={() => save(meta.cta)} className={cn(button,"bg-pink-500 text-slate-950")}><Save className="mr-2 h-4 w-4" />{meta.cta}</button><button onClick={() => autoFill("meta")} className={cn(button,"border border-slate-200 bg-white/10 text-slate-950")}><Wand2 className="mr-2 h-4 w-4" />Smart meta</button><button onClick={() => autoFill("outline")} className={cn(button,"border border-slate-200 bg-white/10 text-slate-950")}><BookOpen className="mr-2 h-4 w-4" />Smart outline</button></div></div><div className="relative z-10 grid grid-cols-2 gap-3"><Metric label="Tasks" value={items.length} icon={FileText} sub="workspace load" /><Metric label="Selected SEO" value={`${selected.seo_score || 0}%`} icon={Gauge} sub="readiness" /><Metric label="Warnings" value={warnings.length} icon={AlertTriangle} sub="blockers" /><Metric label="Logs" value={logs.length} icon={Activity} sub="actions" /></div></div></header>
      <div className="grid gap-6 xl:grid-cols-[340px_1fr_360px]">
        <aside className="space-y-5"><Panel title="Task selector" subtitle="Open any existing SEO/blog operation." icon={Search}><select className={input} value={selectedId} onChange={(e) => { setSelectedId(e.target.value); const found = items.find(i => i.id === e.target.value); if (found) setDraft(found) }}><option value="">New task</option>{items.map(i => <option key={i.id} value={i.id}>{i.title}</option>)}</select><div className="mt-3 grid gap-2">{items.slice(0,8).map(i => <button key={i.id} onClick={() => { setSelectedId(i.id); setDraft(i) }} className={cn(button,"justify-start", selectedId===i.id ? "bg-white text-slate-950" : "bg-slate-100 text-slate-700")}><FileText className="mr-2 h-4 w-4" />{i.title || "Untitled"}</button>)}</div></Panel><Panel title="Status control" subtitle={note} icon={ClipboardCheck}>{SEO_STATUSES.map(s => <button key={s} onClick={() => status(s)} className={cn(button,"mb-2 mr-2", draft.status === s ? "bg-pink-600 text-slate-950" : "bg-pink-50 text-pink-700")}>{SEO_STATUS_LABELS[s]}</button>)}</Panel><Panel title="Workflow map" subtitle="Every stage is actionable." icon={GitBranch}>{statusCounts.map(x => <div key={x.status} className="mb-2 rounded-2xl bg-slate-50 p-3"><div className="flex items-center justify-between"><Badge tone={statusTone(x.status)}>{SEO_STATUS_LABELS[x.status]}</Badge><span className="text-sm font-black text-slate-900">{x.count}</span></div></div>)}</Panel></aside>
        <section className="space-y-5"><Panel title="Core SEO brief" subtitle="Main production fields for senior content branding and communication operations." icon={meta.icon}><div className="grid gap-4 md:grid-cols-2"><Field label="Title"><input className={input} value={draft.title} onChange={(e)=>update({ title:e.target.value, slug: slugify(e.target.value) })} /></Field><Field label="Slug"><input className={input} value={draft.slug} onChange={(e)=>update({ slug:e.target.value })} /></Field><Field label="Content type"><select className={input} value={draft.content_type} onChange={(e)=>update({ content_type:e.target.value as SeoType })}>{Object.entries(SEO_TYPES).map(([k,v]) => <option key={k} value={k}>{v}</option>)}</select></Field><Field label="Priority"><select className={input} value={draft.priority} onChange={(e)=>update({ priority:e.target.value as any })}>{["urgent","high","normal","low"].map(p => <option key={p} value={p}>{p}</option>)}</select></Field><Field label="Owner"><input className={input} value={draft.owner} onChange={(e)=>update({ owner:e.target.value })} /></Field><Field label="Market"><input className={input} value={draft.market} onChange={(e)=>update({ market:e.target.value })} /></Field><Field label="Audience"><input className={input} value={draft.audience} onChange={(e)=>update({ audience:e.target.value })} /></Field><Field label="Service"><input className={input} value={draft.service_name} onChange={(e)=>update({ service_name:e.target.value })} /></Field><Field label="Primary keyword"><input className={input} value={draft.primary_keyword} onChange={(e)=>update({ primary_keyword:e.target.value })} /></Field><Field label="Deadline"><input className={input} value={draft.deadline} onChange={(e)=>update({ deadline:e.target.value })} /></Field></div></Panel><Panel title="Metadata and search intent" subtitle="Control ranking snippet and search behavior." icon={Target}><div className="grid gap-4"><Field label="Search intent"><textarea className={textarea} value={draft.search_intent} onChange={(e)=>update({ search_intent:e.target.value })} /></Field><Field label="Meta title"><input className={input} value={draft.meta_title} onChange={(e)=>update({ meta_title:e.target.value })} /></Field><Field label="Meta description"><textarea className={textarea} value={draft.meta_description} onChange={(e)=>update({ meta_description:e.target.value })} /></Field></div></Panel><Panel title="Content body and structure" subtitle="Outline, draft, links, review notes and publishing details." icon={BookOpen}><div className="grid gap-4"><Field label="Secondary keywords / cluster"><textarea className={textarea} value={draft.secondary_keywords} onChange={(e)=>update({ secondary_keywords:e.target.value })} /></Field><Field label="Outline"><textarea className={textarea} value={draft.outline} onChange={(e)=>update({ outline:e.target.value })} /></Field><Field label="Draft body"><textarea className={cn(textarea,"min-h-[260px]")} value={draft.draft_body} onChange={(e)=>update({ draft_body:e.target.value })} /></Field><Field label="Internal links"><textarea className={textarea} value={draft.internal_links} onChange={(e)=>update({ internal_links:e.target.value })} /></Field><Field label="Review notes"><textarea className={textarea} value={draft.review_notes} onChange={(e)=>update({ review_notes:e.target.value })} /></Field><Field label="Publish URL"><input className={input} value={draft.publish_url} onChange={(e)=>update({ publish_url:e.target.value })} /></Field></div></Panel></section>
        <aside className="space-y-5"><Panel title="Action dock" subtitle="Buttons are wired to local operational state." icon={Zap} dark><div className="grid gap-2"><button onClick={() => save("save")} className={cn(button,"justify-start bg-pink-500 text-slate-950")}><Save className="mr-2 h-4 w-4" />Save</button><button onClick={() => autoFill("intent")} className={cn(button,"justify-start border border-slate-200 bg-white/10 text-slate-950")}><Brain className="mr-2 h-4 w-4" />Generate intent</button><button onClick={() => autoFill("links")} className={cn(button,"justify-start border border-slate-200 bg-white/10 text-slate-950")}><Link2 className="mr-2 h-4 w-4" />Generate links</button><button onClick={() => status("review")} className={cn(button,"justify-start border border-slate-200 bg-white/10 text-slate-950")}><Send className="mr-2 h-4 w-4" />Submit for review</button><button onClick={() => status("approved")} className={cn(button,"justify-start border border-slate-200 bg-white/10 text-slate-950")}><CheckCircle2 className="mr-2 h-4 w-4" />Approve</button><button onClick={() => status("published")} className={cn(button,"justify-start border border-slate-200 bg-white/10 text-slate-950")}><UploadCloud className="mr-2 h-4 w-4" />Publish</button><button onClick={() => remove(false)} className={cn(button,"justify-start border border-slate-200 bg-white/10 text-slate-950")}><Archive className="mr-2 h-4 w-4" />Archive</button><button onClick={() => remove(true)} className={cn(button,"justify-start border border-red-400/30 bg-red-500/20 text-slate-950")}><Trash2 className="mr-2 h-4 w-4" />Delete permanently</button></div></Panel><Panel title="Live readiness" subtitle="Executive quality gates." icon={Gauge}>{[ ["SEO", draft.seo_score], ["Readability", draft.readability_score], ["Conversion", draft.conversion_score] ].map(([label,value]: any) => <div key={label} className="mb-4"><div className="flex justify-between text-xs font-black uppercase tracking-widest text-slate-9500"><span>{label}</span><span>{value}%</span></div><div className="mt-2 h-3 overflow-hidden rounded-full bg-slate-100"><div className="h-full rounded-full bg-pink-500" style={{ width: pct(value) }} /></div></div>)}{warnings.map(w => <div key={w} className="mb-2 rounded-2xl border border-amber-200 bg-amber-50 p-3 text-sm font-bold text-amber-800"><AlertTriangle className="mr-2 inline h-4 w-4" />{w}</div>)}</Panel><Panel title="Operating library" subtitle="Contextual controls for this subpage." icon={Layers3}><div className="grid gap-2">{SEO_SUBPAGE_OPERATING_LIBRARY.slice(0, 12).map(x => <div key={x.id} className="rounded-2xl bg-slate-50 p-3"><Badge tone="pink">{x.gate}</Badge><p className="mt-2 text-sm font-black text-slate-900">{x.control}</p><p className="text-xs font-semibold text-slate-9500">{x.result}</p></div>)}</div></Panel></aside>
      </div>
    </section>
  </main>
}
